1	import { getApiBase } from "@app/lib/getApiBase";
2	
3	import { adminAuthSlice, logout } from "./adminAuthSlice";
4	
5	import { createStore } from "@edu-pwa/core";
6	
7	const ADMIN_LOGIN_PATH = "/admin/login";
8	const ADMIN_TOKEN_KEY = "admin-token";
9	const ADMIN_ROLE_KEY = "admin-role";
10	
11	const loadAuthFromStorage = () => {
12	  try {
13	    const token = sessionStorage.getItem(ADMIN_TOKEN_KEY);
14	    if (token) {
15	      return { token, role: sessionStorage.getItem(ADMIN_ROLE_KEY), isAuthenticated: true };
16	    }
17	  } catch {
18	    // ignore
19	  }
20	  return { token: null, role: null, isAuthenticated: false };
21	};
22	
23	let storeRef: ReturnType<typeof createStore>["store"] | null = null;
24	
25	const { store, baseApi } = createStore({
26	  baseUrl: getApiBase(),
27	  credentials: "include",
28	  getToken: state => (state as { adminAuth?: { token: string | null } }).adminAuth?.token ?? null,
29	  onUnauthorized: () => {
30	    storeRef?.dispatch(logout());
31	    window.location.href = ADMIN_LOGIN_PATH;
32	  },
33	  skipAuthRedirect: args => {
34	    const url = typeof args === "string" ? args : ((args as { url?: string })?.url ?? "");
35	    return url.includes("/subjects/import");
36	  },
37	  tagTypes: ["AdminUser", "Content", "Ktp"],
38	  reducerPath: "adminApi",
39	  staticReducers: {
40	    adminAuth: adminAuthSlice.reducer,
41	  },
42	  preloadedState: {
43	    adminAuth: loadAuthFromStorage(),
44	  },
45	});
46	
47	storeRef = store;
48	
49	store.subscribe(() => {
50	  const { token, role } = (
51	    store.getState() as { adminAuth: { token: string | null; role: string | null } }
52	  ).adminAuth;
53	  if (token) {
54	    sessionStorage.setItem(ADMIN_TOKEN_KEY, token);
55	  } else {
56	    sessionStorage.removeItem(ADMIN_TOKEN_KEY);
57	  }
58	  if (role) {
59	    sessionStorage.setItem(ADMIN_ROLE_KEY, role);
60	  } else {
61	    sessionStorage.removeItem(ADMIN_ROLE_KEY);
62	  }
63	});
64	
65	export { baseApi, store };
66	export type RootState = ReturnType<typeof store.getState>;
67	export type AppDispatch = typeof store.dispatch;
68

1	import { createSlice, type PayloadAction } from "@reduxjs/toolkit";
2	
3	type AdminAuthState = {
4	  token: string | null;
5	  /** Роль вошедшего: 'admin' | 'teacher' (для гейтинга UI; сервер форсит права) */
6	  role: string | null;
7	  isAuthenticated: boolean;
8	};
9	
10	const initialState: AdminAuthState = {
11	  token: null,
12	  role: null,
13	  isAuthenticated: false,
14	};
15	
16	export const adminAuthSlice = createSlice({
17	  name: "adminAuth",
18	  initialState,
19	  reducers: {
20	    setCredentials: (
21	      state,
22	      action: PayloadAction<{ token: string | null; role?: string | null }>,
23	    ) => {
24	      state.token = action.payload.token;
25	      state.role = action.payload.role ?? null;
26	      state.isAuthenticated = Boolean(action.payload.token);
27	    },
28	    logout: state => {
29	      state.token = null;
30	      state.role = null;
31	      state.isAuthenticated = false;
32	    },
33	  },
34	});
35	
36	export const { setCredentials, logout } = adminAuthSlice.actions;
37

