1	import { useMemo, useState } from "react";
2	import { useParams } from "react-router-dom";
3	
4	import { useAppSelector } from "@app/store/hooks";
5	
6	import type { KtpTopic, KtpTopicInput } from "@entities/ktp";
7	import {
8	  useAddKtpTopicMutation,
9	  useDeleteKtpTopicMutation,
10	  useGetKtpCatalogQuery,
11	  useImportKtpTopicsMutation,
12	  useReorderKtpTopicsMutation,
13	  useUpdateKtpTopicMutation,
14	  useUpsertKtpMetaMutation,
15	} from "@entities/ktp";
16	
17	import DeleteOutlineIcon from "@mui/icons-material/DeleteOutline";
18	import KeyboardArrowDownIcon from "@mui/icons-material/KeyboardArrowDown";
19	import KeyboardArrowUpIcon from "@mui/icons-material/KeyboardArrowUp";
20	import {
21	  Alert,
22	  Box,
23	  Button,
24	  Checkbox,
25	  Divider,
26	  FormControlLabel,
27	  IconButton,
28	  Paper,
29	  Stack,
30	  TextField,
31	  Typography,
32	} from "@mui/material";
33	
34	function KtpTopicRow({
35	  topic,
36	  index,
37	  total,
38	  onMove,
39	  onSave,
40	  onDelete,
41	}: {
42	  topic: KtpTopic;
43	  index: number;
44	  total: number;
45	  onMove: (index: number, dir: -1 | 1) => void;
46	  onSave: (body: Partial<KtpTopicInput>) => void;
47	  onDelete: () => void;
48	}) {
49	  const [editing, setEditing] = useState(false);
50	  const [title, setTitle] = useState(topic.title);
51	  const [code, setCode] = useState(topic.code ?? "");
52	  const [description, setDescription] = useState(topic.description ?? "");
53	
54	  const startEdit = () => {
55	    setTitle(topic.title);
56	    setCode(topic.code ?? "");
57	    setDescription(topic.description ?? "");
58	    setEditing(true);
59	  };
60	
61	  const save = () => {
62	    onSave({ title: title.trim() || topic.title, code: code.trim(), description: description.trim() });
63	    setEditing(false);
64	  };
65	
66	  return (
67	    <Paper variant="outlined" sx={{ p: 1.5 }}>
68	      <Stack direction="row" spacing={1} alignItems="flex-start">
69	        <Stack alignItems="center">
70	          <IconButton size="small" disabled={index === 0} onClick={() => onMove(index, -1)}>
71	            <KeyboardArrowUpIcon fontSize="small" />
72	          </IconButton>
73	          <Typography variant="caption" color="text.secondary">
74	            {index + 1}
75	          </Typography>
76	          <IconButton size="small" disabled={index === total - 1} onClick={() => onMove(index, 1)}>
77	            <KeyboardArrowDownIcon fontSize="small" />
78	          </IconButton>
79	        </Stack>
80	
81	        <Box sx={{ flex: 1, minWidth: 0 }}>
82	          {editing ? (
83	            <Stack spacing={1}>
84	              <Stack direction="row" spacing={1}>
85	                <TextField
86	                  size="small"
87	                  label="Код"
88	                  value={code}
89	                  onChange={e => setCode(e.target.value)}
90	                  sx={{ width: 120 }}
91	                />
92	                <TextField
93	                  size="small"
94	                  label="Название"
95	                  fullWidth
96	                  value={title}
97	                  onChange={e => setTitle(e.target.value)}
98	                />
99	              </Stack>
100	              <TextField
101	                size="small"
102	                label="Описание"
103	                fullWidth
104	                multiline
105	                value={description}
106	                onChange={e => setDescription(e.target.value)}
107	              />
108	              <Stack direction="row" spacing={1}>
109	                <Button size="small" variant="contained" onClick={save}>
110	                  Сохранить
111	                </Button>
112	                <Button size="small" onClick={() => setEditing(false)}>
113	                  Отмена
114	                </Button>
115	              </Stack>
116	            </Stack>
117	          ) : (
118	            <Box>
119	              <Typography variant="body2" fontWeight={600}>
120	                {topic.code ? `${topic.code} · ` : ""}
121	                {topic.title}
122	              </Typography>
123	              {topic.description && (
124	                <Typography variant="caption" color="text.secondary">
125	                  {topic.description}
126	                </Typography>
127	              )}
128	            </Box>
129	          )}
130	        </Box>
131	
132	        {!editing && (
133	          <Button size="small" onClick={startEdit}>
134	            Изменить
135	          </Button>
136	        )}
137	        <IconButton size="small" color="error" onClick={onDelete}>
138	          <DeleteOutlineIcon fontSize="small" />
139	        </IconButton>
140	      </Stack>
141	    </Paper>
142	  );
143	}
144	
145	export function KtpCatalogPage() {
146	  const { subjectId = "" } = useParams<{ subjectId: string }>();
147	  const role = useAppSelector(state => state.adminAuth.role);
148	
149	  const { data: catalog, isLoading } = useGetKtpCatalogQuery(subjectId, { skip: !subjectId });
150	  const [addTopic] = useAddKtpTopicMutation();
151	  const [updateTopic] = useUpdateKtpTopicMutation();
152	  const [deleteTopic] = useDeleteKtpTopicMutation();
153	  const [reorderTopics] = useReorderKtpTopicsMutation();
154	  const [upsertMeta] = useUpsertKtpMetaMutation();
155	  const [importTopics] = useImportKtpTopicsMutation();
156	
157	  const [newTitle, setNewTitle] = useState("");
158	  const [yearInput, setYearInput] = useState("");
159	  const [versionInput, setVersionInput] = useState("");
160	  const [importText, setImportText] = useState("");
161	  const [importReplace, setImportReplace] = useState(true);
162	  const [error, setError] = useState<string | null>(null);
163	
164	  const topics = useMemo(
165	    () => (catalog ? [...catalog.topics].sort((a, b) => a.order - b.order) : []),
166	    [catalog],
167	  );
168	
169	  if (role !== "admin") {
170	    return (
171	      <Box sx={{ p: 4 }}>
172	        <Alert severity="warning">Справочник КТП может редактировать только администратор.</Alert>
173	      </Box>
174	    );
175	  }
176	
177	  const run = async (fn: () => Promise<unknown>) => {
178	    setError(null);
179	    try {
180	      await fn();
181	    } catch {
182	      setError("Не удалось выполнить операцию. Попробуйте ещё раз.");
183	    }
184	  };
185	
186	  const handleAdd = () => {
187	    const title = newTitle.trim();
188	    if (!title) return;
189	    void run(async () => {
190	      await addTopic({ subjectId, body: { title } }).unwrap();
191	      setNewTitle("");
192	    });
193	  };
194	
195	  const handleSaveMeta = () => {
196	    const year = yearInput.trim() ? Number(yearInput.trim()) : undefined;
197	    const version = versionInput.trim() ? Number(versionInput.trim()) : undefined;
198	    void run(() => upsertMeta({ subjectId, year, version }).unwrap());
199	  };
200	
201	  const move = (index: number, dir: -1 | 1) => {
202	    const target = index + dir;
203	    if (target < 0 || target >= topics.length) return;
204	    const reordered = [...topics];
205	    const a = reordered[index];
206	    const b = reordered[target];
207	    if (!a || !b) return;
208	    reordered[index] = b;
209	    reordered[target] = a;
210	    void run(() => reorderTopics({ subjectId, orderedTopicIds: reordered.map(t => t._id) }).unwrap());
211	  };
212	
213	  const handleImport = () => {
214	    if (!importText.trim()) return;
215	    let parsed: unknown;
216	    try {
217	      parsed = JSON.parse(importText);
218	    } catch {
219	      setError("Невалидный JSON");
220	      return;
221	    }
222	    const raw = Array.isArray(parsed) ? parsed : (parsed as { topics?: unknown }).topics;
223	    if (!Array.isArray(raw)) {
224	      setError('Ожидается массив тем или объект { "topics": [...] }');
225	      return;
226	    }
227	    void run(async () => {
228	      await importTopics({ subjectId, topics: raw as KtpTopicInput[], replace: importReplace }).unwrap();
229	      setImportText("");
230	    });
231	  };
232	
233	  return (
234	    <Box sx={{ p: { xs: 2, md: 4 }, maxWidth: 900, mx: "auto" }}>
235	      <Typography variant="h5" fontWeight={700} gutterBottom>
236	        Справочник КТП
237	      </Typography>
238	      <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
239	        Канонический упорядоченный список тем предмета. Роудмап строится из КТП: темы книг (разных
240	        классов) мапятся на эти темы.
241	      </Typography>
242	
243	      {error && (
244	        <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
245	          {error}
246	        </Alert>
247	      )}
248	
249	      <Paper variant="outlined" sx={{ p: 2, mb: 3 }}>
250	        <Stack direction="row" spacing={2} alignItems="flex-end" flexWrap="wrap">
251	          <TextField
252	            label="Год"
253	            size="small"
254	            value={yearInput}
255	            onChange={e => setYearInput(e.target.value)}
256	            placeholder={catalog?.year ? String(catalog.year) : "2026"}
257	            sx={{ width: 120 }}
258	          />
259	          <TextField
260	            label="Версия"
261	            size="small"
262	            value={versionInput}
263	            onChange={e => setVersionInput(e.target.value)}
264	            placeholder={catalog ? String(catalog.version) : "1"}
265	            sx={{ width: 120 }}
266	          />
267	          <Button variant="outlined" onClick={handleSaveMeta}>
268	            Сохранить
269	          </Button>
270	        </Stack>
271	      </Paper>
272	
273	      <Typography variant="subtitle1" fontWeight={600} sx={{ mb: 1 }}>
274	        Темы КТП ({topics.length})
275	      </Typography>
276	
277	      {isLoading && <Typography variant="body2">Загрузка…</Typography>}
278	      {!isLoading && topics.length === 0 && (
279	        <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
280	          Тем пока нет. Добавьте вручную или импортируйте JSON ниже.
281	        </Typography>
282	      )}
283	
284	      <Stack spacing={1} sx={{ mb: 2 }}>
285	        {topics.map((topic, index) => (
286	          <KtpTopicRow
287	            key={topic._id}
288	            topic={topic}
289	            index={index}
290	            total={topics.length}
291	            onMove={move}
292	            onSave={body => void run(() => updateTopic({ subjectId, topicId: topic._id, body }).unwrap())}
293	            onDelete={() => void run(() => deleteTopic({ subjectId, topicId: topic._id }).unwrap())}
294	          />
295	        ))}
296	      </Stack>
297	
298	      <Stack direction="row" spacing={1} sx={{ mb: 4 }}>
299	        <TextField
300	          size="small"
301	          fullWidth
302	          label="Новая тема КТП"
303	          value={newTitle}
304	          onChange={e => setNewTitle(e.target.value)}
305	          onKeyDown={e => {
306	            if (e.key === "Enter") handleAdd();
307	          }}
308	        />
309	        <Button variant="contained" onClick={handleAdd}>
310	          Добавить
311	        </Button>
312	      </Stack>
313	
314	      <Divider sx={{ mb: 3 }} />
315	
316	      <Typography variant="subtitle1" fontWeight={600} sx={{ mb: 1 }}>
317	        Массовый импорт (JSON)
318	      </Typography>
319	      <Typography variant="caption" color="text.secondary" component="p" sx={{ mb: 1 }}>
