25	export function SubjectWorkspacePage() {
26	  const { subjectId } = useParams<{ subjectId: string }>();
27	  const [searchParams, setSearchParams] = useSearchParams();
28	
29	  const { data: subject, isLoading, error } = useGetSubjectByIdQuery(subjectId!, { skip: !subjectId });
30	  const { data: ktpCatalog } = useGetKtpCatalogQuery(subjectId!, { skip: !subjectId });
31	  const { data: roadmap } = useGetCanonicalRoadmapQuery(subjectId!, { skip: !subjectId });
32	  const [updateSubject] = useUpdateSubjectMutation();
33	
34	  const [snack, setSnack] = useState<{ msg: string; severity: "success" | "error" } | null>(null);
35	  const flash: Flash = (msg, severity = "success") => setSnack({ msg, severity });
36	
37	  useEffect(() => {
38	    if (subject) recordRecentSubject({ id: subject._id, title: subject.title, subjectKind: subject.subjectKind });
39	  }, [subject]);
40	
41	  if (!subjectId) return <Alert severity="error" sx={{ m: 4, borderRadius: 3 }}>subjectId не указан</Alert>;
42	  if (isLoading) return <Box sx={{ display: "flex", justifyContent: "center", py: 10 }}><CircularProgress size={40} /></Box>;
43	  if (error) return <Alert severity="error" sx={{ m: 4, borderRadius: 3 }}>Ошибка загрузки предмета</Alert>;
44	  if (!subject) return <Alert severity="error" sx={{ m: 4, borderRadius: 3 }}>Предмет не найден</Alert>;
45	
46	  const sid = subject._id;
47	  const ktpTopics = ktpCatalog ? [...ktpCatalog.topics].sort((a, b) => a.order - b.order) : [];
48	  const status = computePipelineStatus(subject, ktpCatalog, roadmap);
49	
50	  const tabParam = searchParams.get("tab") as WorkspaceTab | null;
51	  const firstIncomplete = TABS.find(k => status[k].state !== "done") ?? "ktp";
52	  const activeTab: WorkspaceTab = tabParam && TABS.includes(tabParam) ? tabParam : firstIncomplete;
53	
54	  const setTab = (tab: WorkspaceTab) => {
55	    const next = new URLSearchParams(searchParams);
56	    next.set("tab", tab);
57	    setSearchParams(next, { replace: true });
58	  };
59	
60	  return (
61	    <Box sx={{ p: { xs: 2.5, md: 4 }, maxWidth: 1000, mx: "auto", display: "flex", flexDirection: "column", gap: 3 }}>
