80	      {activeTab === "ktp" && <KtpPanel subjectId={sid} />}
81	      {activeTab === "content" && <ContentTreePanel subject={subject} ktpTopics={ktpTopics} flash={flash} />}
82	      {activeTab === "mapping" && <MappingBoardPanel subject={subject} catalog={ktpCatalog} flash={flash} />}
83	      {activeTab === "roadmap" && <RoadmapPanel subjectId={sid} flash={flash} />}
84	
85	      <Snackbar
