90	      >
91	        {snack ? (
92	          <Alert severity={snack.severity} variant="filled" onClose={() => setSnack(null)} sx={{ width: "100%" }}>
93	            {snack.msg}
94	          </Alert>
95	        ) : undefined}
96	      </Snackbar>
97	    </Box>
98	  );
99	}
