1	import type { KtpCatalog } from "@entities/ktp";
2	import type { CanonicalRoadmapResponse, Subject } from "@entities/subject";
3	
4	import { buildKtpReverseIndex } from "./ktpReverseIndex";
5	
6	/** Состояние шага пайплайна: готово / частично / пусто. */
7	export type StepState = "done" | "partial" | "empty";
8	
9	export interface PipelineStatus {
10	  ktp: { count: number; state: StepState };
11	  content: { books: number; chapters: number; topics: number; paragraphs: number; state: StepState };
12	  mapping: { mappedKtp: number; totalKtp: number; orphanTopics: number; state: StepState };
13	  roadmap: { built: boolean; nodes: number; version: number | null; state: StepState };
14	}
15	
16	/**
17	 * Считает статусы 4 шагов пайплайна предмета: КТП → Контент → Маппинг → Роудмап.
18	 * Всё выводится клиентски из уже загруженных данных (бэкенд не трогаем).
19	 */
20	export function computePipelineStatus(
21	  subject: Subject | undefined,
22	  catalog: KtpCatalog | null | undefined,
23	  roadmap: CanonicalRoadmapResponse | undefined,
24	): PipelineStatus {
25	  const books = subject?.books ?? [];
26	  const chapters = books.reduce((s, b) => s + b.chapters.length, 0);
27	  const topics = books.reduce((s, b) => s + b.chapters.reduce((cs, c) => cs + c.topics.length, 0), 0);
28	  const paragraphs = books.reduce(
29	    (s, b) =>
30	      s + b.chapters.reduce((cs, c) => cs + c.topics.reduce((ts, t) => ts + t.paragraphs.length, 0), 0),
31	    0,
32	  );
33	
34	  const ktpCount = catalog?.topics.length ?? 0;
35	
36	  let mappedKtp = 0;
37	  let orphanTopics = 0;
38	  if (subject) {
39	    const { byKtpId, orphans } = buildKtpReverseIndex(subject, catalog);
40	    mappedKtp = [...byKtpId.values()].filter(arr => arr.length > 0).length;
41	    orphanTopics = orphans.length;
42	  }
43	
44	  const nodes = roadmap?.nodes.length ?? 0;
45	
46	  const mappingState: StepState =
47	    ktpCount === 0 || mappedKtp === 0
48	      ? "empty"
49	      : mappedKtp === ktpCount && orphanTopics === 0
50	        ? "done"
51	        : "partial";
52	
53	  return {
54	    ktp: { count: ktpCount, state: ktpCount > 0 ? "done" : "empty" },
55	    content: {
56	      books: books.length,
57	      chapters,
58	      topics,
59	      paragraphs,
60	      state: paragraphs > 0 ? "done" : topics > 0 ? "partial" : "empty",
61	    },
62	    mapping: { mappedKtp, totalKtp: ktpCount, orphanTopics, state: mappingState },
63	    roadmap: {
64	      built: nodes > 0,
65	      nodes,
66	      version: roadmap?.version ?? null,
67	      state: nodes > 0 ? "done" : "empty",
68	    },
69	  };
70	}
