2	 * Достаёт человекочитаемое сообщение из ошибки RTK Query (.unwrap()).
3	 * Бэкенд отдаёт { message } в data; иначе — переданный fallback.
4	 */
5	export function apiErrorMessage(
6	  e: unknown,
7	  fallback = "Не удалось выполнить операцию. Попробуйте ещё раз.",
8	): string {
9	  const data = (e as { data?: { message?: unknown } } | undefined)?.data;
10	  if (data && typeof data.message === "string" && data.message.trim()) return data.message.trim();
